+            tls_port: Some(0),
+            cert_file: None,
+            key_file: None,
+            ca_file: None,
+            protocols: vec![TlsProtocol::TlsV1_2],
+            ciphers: None,
+            auth_clients: TlsAuthClients::Required,
+            cluster_announce_tls_port: None,
+            max_new_tls_connections_per_cycle: 16,
+        };
+
